const LANDING = '<!DOCTYPE html>\n<!-- saved from url=(0017)https://bligo.ai/ -->\n<html lang="en"><head><meta http-equiv="Content-Type" content="text/html; charset=UTF-8">\n  \n  <meta name="viewport" content="width=device-width, initial-scale=1.0">\n  <title>Real Connections, Curated by AI | Bligo</title>\n  <link rel="preconnect" href="https://fonts.googleapis.com/">\n  <link rel="preconnect" href="https://fonts.gstatic.com/" crossorigin="">\n  <link href="./Real Connections, Curated by AI _ Bligo_files/css2" rel="stylesheet">\n  <meta property="og:title" content="Real Connections, Curated by AI">\n  <meta property="og:description" content="Unlock new connections across your personal network. Review intelligent matches and connect by mutual introduction.">\n  <meta property="og:type" content="website">\n  <meta property="og:url" content="https://bligo.ai">\n  <meta property="og:image" content="https://bligo.ai/og-image.png">\n  <meta property="og:image:width" content="1200">\n  <meta property="og:image:height" content="630">\n  <meta name="twitter:card" content="summary_large_image">\n  <meta name="twitter:title" content="Real Connections, Curated by AI">\n  <meta name="twitter:description" content="Unlock new connections across your personal network.">\n  <meta name="twitter:image" content="https://bligo.ai/og-image.png">\n  <style>\n    :root {\n      color-scheme: dark;\n      --bg: #05060a;\n      --card: #0e1118;\n      --primary: #68f0c4;\n      --soft: #9ca3af;\n      --white: #f8fafc;\n      --border: rgba(255,255,255,0.08);\n    }\n    * {\n      box-sizing: border-box;\n      margin: 0;\n      padding: 0;\n    }\n    html { scroll-behavior: smooth; }\n    body {\n      font-family: \'Inter\', sans-serif;\n      background: radial-gradient(circle at top, rgba(104,240,196,0.08), transparent 45%), var(--bg);\n      color: var(--white);\n      line-height: 1.6;\n      min-height: 100vh;\n    }\n    header {\n      position: sticky;\n      top: 0;\n      z-index: 50;\n      backdrop-filter: blur(10px);\n      background: rgba(5,6,10,0.72);\n      border-bottom: 1px solid var(--border);\n      padding: 16px 4vw;\n      display: flex;\n      justify-content: space-between;\n      align-items: center;\n      gap: 12px;\n    }\n    .logo {\n      display: flex;\n      align-items: center;\n      gap: 16px;\n    }\n    .logo-image {\n      height: 42px;\n      width: auto;\n      display: block;\n      border-radius: 12px;\n      border: 1px solid var(--border);\n    }\n    .hero {\n      padding: 60px 4vw 40px;\n      display: grid;\n      grid-template-columns: repeat(auto-fit,minmax(320px,1fr));\n      gap: 32px;\n      align-items: center;\n    }\n    h1 {\n      font-size: clamp(2.6rem, 5vw, 3.6rem);\n      line-height: 1.1;\n      margin-bottom: 24px;\n    }\n    .hero p {\n      color: var(--soft);\n      font-size: 1.1rem;\n      margin-bottom: 32px;\n      max-width: 540px;\n    }\n    .cta-group {\n      display: flex;\n      flex-wrap: wrap;\n      gap: 16px;\n    }\n    .btn {\n      padding: 14px 26px;\n      border-radius: 999px;\n      border: none;\n      font-weight: 600;\n      cursor: pointer;\n      text-decoration: none;\n      transition: transform 0.2s ease, box-shadow 0.2s ease;\n    }\n    .btn-primary {\n      background: linear-gradient(120deg, #68f0c4, #5b8dff);\n      color: #05060a;\n      box-shadow: 0 15px 35px rgba(91,141,255,0.3);\n    }\n    .btn-secondary {\n      background: transparent;\n      color: var(--white);\n      border: 1px solid var(--border);\n    }\n    .btn:hover {\n      transform: translateY(-2px);\n    }\n    section {\n      padding: 60px 4vw;\n    }\n    h2 {\n      font-size: 2rem;\n      margin-bottom: 16px;\n    }\n    .section-subline {\n      color: var(--soft);\n      max-width: 560px;\n      margin: -8px 0 24px;\n    }\n    .eyebrow {\n      text-transform: uppercase;\n      font-size: 0.85rem;\n      letter-spacing: 0.12em;\n      color: var(--soft);\n      margin-bottom: 12px;\n    }\n    .grid-3 {\n      display: grid;\n      grid-template-columns: repeat(auto-fit,minmax(240px,1fr));\n      gap: 20px;\n      margin-top: 32px;\n    }\n    .card {\n      background: var(--card);\n      border: 1px solid var(--border);\n      border-radius: 20px;\n      padding: 24px;\n      min-height: 230px;\n      display: flex;\n      flex-direction: column;\n      gap: 12px;\n    }\n    .badge {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      font-size: 0.85rem;\n      color: var(--primary);\n    }\n    .privacy {\n      background: rgba(14,17,24,0.8);\n      border: 1px solid var(--border);\n      border-radius: 28px;\n      display: grid;\n      grid-template-columns: repeat(auto-fit,minmax(280px,1fr));\n      gap: 28px;\n      align-items: center;\n      padding: 40px;\n    }\n    .privacy ul {\n      list-style: none;\n      display: flex;\n      flex-direction: column;\n      gap: 12px;\n    }\n    .privacy li::before {\n      content: \'• \';\n      color: var(--primary);\n    }\n    .waitlist {\n      padding: 60px 4vw 80px;\n      display: grid;\n      grid-template-columns: repeat(auto-fit,minmax(320px,1fr));\n      gap: 32px;\n      align-items: center;\n    }\n    form {\n      background: var(--card);\n      border: 1px solid var(--border);\n      border-radius: 24px;\n      padding: 32px;\n      display: flex;\n      flex-direction: column;\n      gap: 18px;\n    }\n    label {\n      font-size: 0.95rem;\n      font-weight: 500;\n    }\n    input, textarea {\n      padding: 14px;\n      border-radius: 14px;\n      border: 1px solid rgba(255,255,255,0.15);\n      background: rgba(255,255,255,0.02);\n      color: var(--white);\n      font-size: 1rem;\n    }\n    footer {\n      padding: 30px 4vw 50px;\n      font-size: 0.9rem;\n      color: var(--soft);\n      border-top: 1px solid var(--border);\n      text-align: center;\n    }\n    @media (max-width: 640px) {\n      header, section, .waitlist, .hero {\n        padding-left: 5vw;\n        padding-right: 5vw;\n      }\n      .cta-group {\n        flex-direction: column;\n        width: 100%;\n      }\n      .btn {\n        width: 100%;\n        text-align: center;\n      }\n    }\n  \n    @media (max-width: 760px) {\n      header { padding: 12px 4vw; }\n      .logo-image { height: 34px; }\n      .hero { padding: 34px 4vw 24px; grid-template-columns: 1fr; gap: 20px; }\n      h1 { font-size: clamp(2rem, 9vw, 2.6rem); margin-bottom: 16px; }\n      .hero p { font-size: 1rem; margin-bottom: 20px; }\n      .cta-group { width: 100%; }\n      .btn { width: 100%; text-align: center; }\n      section { padding: 42px 4vw; }\n      .privacy { padding: 22px; border-radius: 18px; }\n      .waitlist { padding: 40px 4vw 64px; grid-template-columns: 1fr; }\n      form { padding: 20px; border-radius: 16px; }\n    }\n  </style>\n</head>\n<body>\n  <header>\n    <div class="logo">\n      <img src="data:image/png;base64," alt="Bligo logo" class="logo-image">\n      <div>\n        <strong>Bligo</strong>\n        <div style="font-size:0.85rem;color:var(--soft)">AI-driven introductions</div>\n      </div>\n    </div>\n    <a href="/signin" class="btn btn-primary">Sign In</a><a href="https://bligo.ai/#waitlist" class="btn btn-secondary">Join Waitlist</a>\n  </header>\n\n  <section class="hero">\n    <div>\n      <div class="eyebrow">Meet Bligo</div>\n      <h1>Real connections, curated by AI.</h1>\n      <p class="subhead">Your own smarter network.</p>\n      <p>Bligo helps you unlock new connections across your personal network. Share your intent, and AI surfaces high-fit matches within your direct and extended circles. You approve the introduction, they accept, and a private conversation opens.</p>\n      <div class="cta-group">\n        <a href="https://bligo.ai/#waitlist" class="btn btn-primary">Connect Your Personal AI</a>\n\n      </div>\n    </div>\n  </section>\n\n  <section id="how">\n    <div class="eyebrow">How it works</div>\n    <h2>Tell AI what you’re looking for.</h2>\n    <p class="section-subline">Discover your best-fit connections.</p>\n    <div class="grid-3">\n      <div class="card">\n        <div class="badge">01 · Activate</div>\n        <h3>Set your intent</h3>\n        <p>Create your profile, define your goals, and control exactly what’s visible and what stays private.</p>\n      </div>\n      <div class="card">\n        <div class="badge">02 · Match</div>\n        <h3>Review connections</h3>\n        <p>AI identifies and ranks high-fit matches across your direct and extended network based on your intent.</p>\n      </div>\n      <div class="card">\n        <div class="badge">03 · Introduce</div>\n        <h3>Connect with consent</h3>\n        <p>Approve the introduction, send a soft request, and converse only when the other person accepts.</p>\n      </div>\n    </div>\n  </section>\n\n  <section>\n    <div class="eyebrow">Use cases</div>\n    <h2>Built for real-world connections.</h2>\n    <div class="grid-3">\n      <div class="card">\n        <div class="badge">Professional Introductions</div>\n        <h3>Find the right expert.</h3>\n        <p>Looking for a realtor, attorney, or contractor? Bligo surfaces trusted professionals within your network—friends-of-friends included—based on your exact needs and location. You review the match and open a soft introduction with confidence.</p>\n      </div>\n      <div class="card">\n        <div class="badge">Shared Plans &amp; Hobbies</div>\n        <h3>Discover who’s doing what you’re doing.</h3>\n        <p>Planning a ski trip? Bligo can show you which connections are heading to the same place—giving you the option to coordinate or connect.</p>\n      </div>\n      <div class="card">\n        <div class="badge">Meaningful New Connections</div>\n        <h3>Meet people who genuinely align.</h3>\n        <p>Love the same restaurants and music? Bligo highlights high-overlap introductions within your extended network so you can open a thoughtful conversation and see where it leads.</p>\n      </div>\n    </div>\n  </section>\n\n  <section class="privacy">\n    <div>\n      <div class="eyebrow">Privacy &amp; Safety</div>\n      <h2>You stay in control.</h2>\n      <p>Bligo is human-led and consent-based. Every data field is optional, every action is logged, and nothing moves forward unless you approve it.</p>\n    </div>\n    <ul>\n      <li>Intent and privacy toggles for every data point.</li>\n      <li>Audit trail of each approved introduction.</li>\n      <li>Both sides must accept before a conversation opens.</li>\n      <li>Private, permission-based conversations with explicit acceptance from both sides.</li>\n    </ul>\n  </section>\n\n  <section>\n    <div class="eyebrow">What\'s next</div>\n    <h2>Built for trusted, high-signal intros.</h2>\n    <div class="grid-3">\n      <div class="card"><div class="badge">Q1</div><h3>Intent Profiles</h3><p>Fine-grained controls for what your AI can share publicly vs privately.</p></div>\n      <div class="card"><div class="badge">Q2</div><h3>Trust Layer</h3><p>Mutual-consent intros with transparent reason codes for every match.</p></div>\n      <div class="card"><div class="badge">Q3</div><h3>Operator Feed</h3><p>A live opportunity feed built from your preferences and trusted network graph.</p></div>\n    </div>\n  </section>\n\n  <section class="waitlist" id="waitlist">\n    <div>\n      <div class="eyebrow">Join the waitlist</div>\n      <h2>Lead with intent.</h2>\n      <p>Early access includes guided onboarding, intent templates, and a private operator community. Spots are limited.</p>\n    </div>\n    <form id="waitlist-form">\n      <label for="email">Email*</label>\n      <input type="email" id="email" name="email" placeholder="you@company.com" required="">\n      <label for="role">Role / Specialty</label>\n      <input type="text" id="role" name="role" placeholder="Developer, Operator, GC, Investor...">\n      <label for="needs">What should AI help you find?</label>\n      <textarea id="needs" name="needs" rows="4" placeholder="Deal flow, project squads, casual meetups..."></textarea>\n      <button type="submit" class="btn btn-primary" id="submit-btn">Save my spot</button>\n      <p id="form-status" style="font-size:0.95rem;color:var(--soft)"></p>\n    </form>\n  </section>\n\n  <footer>\n    © <span id="year"></span> Bligo. Intent-driven introductions.\n  <div style="font-size:11px;opacity:.75;margin-top:6px">v1.001.006</div></footer>\n\n  <script>\n    const form = document.getElementById(\'waitlist-form\');\n    const statusEl = document.getElementById(\'form-status\');\n    const submitBtn = document.getElementById(\'submit-btn\');\n    if (form && statusEl && submitBtn) {\n      form.addEventListener(\'submit\', async (event) => {\n        event.preventDefault();\n        submitBtn.disabled = true;\n        submitBtn.style.opacity = \'0.7\';\n        statusEl.textContent = \'Sending...\';\n        try {\n          const formData = new FormData(form);\n          const res = await fetch(\'https://formsubmit.co/ajax/info@whiteplainspm.net\', {\n            method: \'POST\',\n            headers: { \'Accept\': \'application/json\' },\n            body: formData\n          });\n          if (res.ok) {\n            form.reset();\n            statusEl.textContent = \'You are in. We\'ll reach out soon.\';\n          } else {\n            statusEl.textContent = \'Submit failed. Email info@bligo.ai and we\'ll add you manually.\';\n          }\n        } catch (err) {\n          statusEl.textContent = \'Network issue. Email info@bligo.ai and we\'ll add you manually.\';\n        } finally {\n          submitBtn.disabled = false;\n          submitBtn.style.opacity = \'1\';\n        }\n      });\n    }\n    const y = document.getElementById(\'year\');\n    if (y) y.textContent = new Date().getFullYear();\n  </script>\n<script defer="" src="./Real Connections, Curated by AI _ Bligo_files/v8c78df7c7c0f484497ecbca7046644da1771523124516" integrity="sha512-8DS7rgIrAmghBFwoOTujcf6D9rXvH8xm8JQ1Ja01h9QX8EzXldiszufYa4IFfKdLUKTTrnSFXLDkUEOTrZQ8Qg==" data-cf-beacon="{&quot;version&quot;:&quot;2024.11.0&quot;,&quot;token&quot;:&quot;ead072d219e4471ca7fbd81a49a6d3fc&quot;,&quot;r&quot;:1,&quot;server_timing&quot;:{&quot;name&quot;:{&quot;cfCacheStatus&quot;:true,&quot;cfEdge&quot;:true,&quot;cfExtPri&quot;:true,&quot;cfL4&quot;:true,&quot;cfOrigin&quot;:true,&quot;cfSpeedBrain&quot;:true},&quot;location_startswith&quot;:null}}" crossorigin="anonymous"></script>\n\n\n\n</body></html>';
function signin(){return `<!doctype html><html><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1"/><title>Sign In | Bligo</title><style>body{font-family:Inter,Arial,sans-serif;background:#0b1220;color:#fff;margin:0}.w{max-width:520px;margin:70px auto;padding:0 16px}.c{background:#111827;border:1px solid #1f2937;border-radius:12px;padding:16px}.tabs{display:flex;gap:8px;margin-bottom:14px}.tab{padding:8px 12px;border:1px solid #334155;border-radius:10px;text-decoration:none;color:#fff}.tab.active{background:#2563eb;border-color:#2563eb}.in{width:100%;padding:10px;margin:8px 0;border:1px solid #334155;border-radius:10px;background:#0f172a;color:#fff}.btn{padding:10px 14px;border-radius:10px;background:#2563eb;color:#fff;border:0;cursor:pointer}</style></head><body><div class="w"><div class="c"><div class="tabs"><a class="tab active" href="/signin">Sign In</a><a class="tab" href="/signup">Sign Up</a></div><h2>Sign in to Bligo</h2><form id="f"><input id="e" class="in" type="email" placeholder="Email" required/><input id="p" class="in" type="password" placeholder="Password" required/><button class="btn" type="submit">Sign In</button></form><p id="err" style="display:none;color:#fca5a5">Invalid email or password.</p></div></div><script>document.getElementById('f').addEventListener('submit',ev=>{ev.preventDefault();const e=document.getElementById('e').value.trim();const p=document.getElementById('p').value;const ok=/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e)&&p.length>=6;if(!ok){document.getElementById('err').style.display='block';return;}localStorage.setItem('bligo_auth',JSON.stringify({email:e,at:Date.now()}));location.href='/app';});<\/script></body></html>`;}
function signup(){return `<!doctype html><html><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1"/><title>Sign Up | Bligo</title><style>body{font-family:Inter,Arial,sans-serif;background:#0b1220;color:#fff;margin:0}.w{max-width:520px;margin:70px auto;padding:0 16px}.c{background:#111827;border:1px solid #1f2937;border-radius:12px;padding:16px}.tabs{display:flex;gap:8px;margin-bottom:14px}.tab{padding:8px 12px;border:1px solid #334155;border-radius:10px;text-decoration:none;color:#fff}.tab.active{background:#2563eb;border-color:#2563eb}.in{width:100%;padding:10px;margin:8px 0;border:1px solid #334155;border-radius:10px;background:#0f172a;color:#fff}.btn{padding:10px 14px;border-radius:10px;background:#2563eb;color:#fff;border:0;cursor:pointer}</style></head><body><div class="w"><div class="c"><div class="tabs"><a class="tab" href="/signin">Sign In</a><a class="tab active" href="/signup">Sign Up</a></div><h2>Create your account</h2><form id="s"><input id="n" class="in" placeholder="Full name" required/><input id="e" class="in" type="email" placeholder="Email" required/><input id="p" class="in" type="password" placeholder="Password (min 6)" required/><button class="btn" type="submit">Create Account</button></form><p id="msg" style="display:none;color:#86efac">Account created. Redirecting…</p></div></div><script>document.getElementById('s').addEventListener('submit',ev=>{ev.preventDefault();const n=document.getElementById('n').value.trim();const e=document.getElementById('e').value.trim();const p=document.getElementById('p').value;const ok=n.length>1&&/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e)&&p.length>=6;if(!ok)return;localStorage.setItem('bligo_user',JSON.stringify({name:n,email:e}));localStorage.setItem('bligo_auth',JSON.stringify({email:e,at:Date.now()}));document.getElementById('msg').style.display='block';setTimeout(()=>location.href='/app',600);});<\/script></body></html>`;}
function app(){return `<!doctype html><html><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1"/><title>Bligo — Signed In</title></head><body style="font-family:Inter,Arial,sans-serif;margin:40px;background:#f3f6fb"><h1>Bligo — Signed In</h1><p id="who"></p><p><a href="/">Landing</a> · <a href="#" id="o">Sign Out</a></p><script>const a=JSON.parse(localStorage.getItem('bligo_auth')||'null');if(!a){location.href='/signin';}else{document.getElementById('who').textContent='Signed in as: '+a.email;}document.getElementById('o').onclick=(e)=>{e.preventDefault();localStorage.removeItem('bligo_auth');location.href='/';};<\/script></body></html>`;}
async function handle(r){const p=new URL(r.url).pathname;const h=(p==='/'||p==='')?LANDING:(p==='/signin'||p==='/signin/')?signin():(p==='/signup'||p==='/signup/')?signup():(p==='/app'||p==='/app/')?app():LANDING;return new Response(h,{headers:{'content-type':'text/html; charset=UTF-8','cache-control':'no-store'}});}